import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.CMAFtOGK.js";const c=JSON.parse('{"title":"04 社会主义改造","description":"政治理论 · 04 社会主义改造","frontmatter":{"title":"04 社会主义改造","description":"政治理论 · 04 社会主义改造","category":"politics-note"},"headers":[],"relativePath":"posts/politics/notes/04-社会主义改造.md","filePath":"posts/politics/notes/04-社会主义改造.md","lastUpdated":1784753089000}'),s={name:"posts/politics/notes/04-社会主义改造.md"};function r(n,t,d,i,h,g){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="_04-社会主义改造理论" tabindex="-1">04 社会主义改造理论 <a class="header-anchor" href="#_04-社会主义改造理论" aria-label="Permalink to &quot;04 社会主义改造理论&quot;">​</a></h1><blockquote><p>🎯 <strong>一句话</strong>：过渡时期总路线 = <strong>一化三改</strong>（一体两翼）。</p></blockquote><hr><h2 id="一、过渡时期总路线" tabindex="-1">一、过渡时期总路线 <a class="header-anchor" href="#一、过渡时期总路线" aria-label="Permalink to &quot;一、过渡时期总路线&quot;">​</a></h2><p><strong>从中华人民共和国成立，到社会主义改造基本完成</strong>，这是一个过渡时期。党在这个过渡时期的总路线和总任务是：</p><blockquote><p>要在一个相当长的时期内，逐步实现国家的<strong>社会主义工业化</strong>，并逐步实现国家对<strong>农业、手工业和资本主义工商业</strong>的社会主义改造。</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">名称</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;">一化</td><td style="text-align:left;">社会主义工业化（主体）</td></tr><tr><td style="text-align:left;">三改</td><td style="text-align:left;">农业、手工业、资本主义工商业的社会主义改造（两翼）</td></tr></tbody></table><hr><h2 id="二、改造道路要点" tabindex="-1">二、改造道路要点 <a class="header-anchor" href="#二、改造道路要点" aria-label="Permalink to &quot;二、改造道路要点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">对象</th><th style="text-align:left;">道路/形式</th><th style="text-align:left;">结果</th></tr></thead><tbody><tr><td style="text-align:left;">农业</td><td style="text-align:left;">互助组 → 初级社 → 高级社</td><td style="text-align:left;">集体所有制</td></tr><tr><td style="text-align:left;">手工业</td><td style="text-align:left;">供销小组 → 供销合作社 → 生产合作社</td><td style="text-align:left;">集体所有制</td></tr><tr><td style="text-align:left;">资本主义工商业</td><td style="text-align:left;">和平赎买；加工订货、公私合营等</td><td style="text-align:left;">全民所有制</td></tr></tbody></table><p><strong>1956 年底</strong>：社会主义改造基本完成 → 社会主义基本制度在中国确立。</p><hr><h2 id="三、闭卷挑战" tabindex="-1">三、闭卷挑战 <a class="header-anchor" href="#三、闭卷挑战" aria-label="Permalink to &quot;三、闭卷挑战&quot;">​</a></h2><p><strong>1.</strong> “一化三改”分别指什么？</p><blockquote><p><strong>点击查看答案与解析</strong> 一化：社会主义工业化；三改：对农业、手工业、资本主义工商业的社会主义改造。</p></blockquote><p><strong>2.</strong> 社会主义基本制度在中国确立的标志性时间？</p><blockquote><p><strong>点击查看答案与解析</strong> 1956 年底社会主义改造基本完成。</p></blockquote><p>返回：03-新民主主义革命 · <a href="/zhuan-sheng-ben-notes/posts/politics/">政治</a></p>',18)])])}const f=e(s,[["render",r]]);export{c as __pageData,f as default};
